package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.ApiResponse;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.score.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;import java.time.OffsetDateTime;import java.util.Map;
@RestController @RequestMapping("/internal/supplier/v1/performance/events")public class PerformanceFactOpenApiController{private final PerformanceFactEventConsumerApplicationService service;public PerformanceFactOpenApiController(PerformanceFactEventConsumerApplicationService service){this.service=service;}@PostMapping public ApiResponse<Void> consume(@Valid @RequestBody Request b,HttpServletRequest r){String source=r.getHeader("X-Source-System"),code=r.getHeader("X-Event-Code");if(source==null||code==null)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"缺少事件请求头");service.consume(new PerformanceFactEvent(source,code,b.eventType(),b.supplierId(),b.sourceNo(),b.metricValue(),b.occurredAt(),b.payload()));return ApiResponse.success(null,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}public record Request(@NotBlank String eventType,@Positive long supplierId,String sourceNo,@NotNull BigDecimal metricValue,@NotNull OffsetDateTime occurredAt,Map<String,Object> payload){} }
